#!/usr/bin/env node

/**
 * Block Generated Files Hook (PreToolUse / Edit|Write)
 *
 * Denies edits to files that are produced by tooling rather than hand-written.
 * Tells Claude how to regenerate them instead.
 */

import { readFileSync } from 'fs'

const input = JSON.parse(readFileSync(0, 'utf-8'))
const filePath = input?.tool_input?.file_path

if (!filePath) {
  process.exit(0)
}

const projectDir = process.env.CLAUDE_PROJECT_DIR || ''
const rel = filePath.startsWith(projectDir + '/') ? filePath.slice(projectDir.length + 1) : filePath

const rules = [
  {
    test: (p) => /^dist\//.test(p),
    reason: '`dist/` is build output from `pnpm build`. Never edit it by hand — change the source under `src/` and rebuild.',
  },
  {
    test: (p) => p === 'pnpm-lock.yaml',
    reason: '`pnpm-lock.yaml` is generated by pnpm. To change dependencies run `pnpm add` / `pnpm remove` / `pnpm update` and let pnpm rewrite the lockfile.',
  },
]

const matched = rules.find((r) => r.test(rel))

if (matched) {
  const out = {
    hookSpecificOutput: {
      hookEventName: 'PreToolUse',
      permissionDecision: 'deny',
      permissionDecisionReason: matched.reason,
    },
  }
  console.log(JSON.stringify(out))
  process.exit(0)
}

process.exit(0)
